<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>PagerDuty | ServiceNow Cloud Observability Integration</title>
    <style>
        :root {
            --pd-green: #00805a;
            --pd-green-dark: #006648;
            --pd-black: #2a2f36;
            --pd-gray-dark: #53585f;
            --pd-gray-medium: #8c929a;
            --pd-gray-light: #f5f5f5;
            --pd-white: #ffffff;
            --pd-border: #e0e0e0;
            --resource-report: #0070f0;
            --resource-datasheet: #00805a;
            --resource-solutions: #1a237e;
            --resource-video: #f8bbd0;
            --resource-resource: #bbdefb;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
            color: var(--pd-black);
            line-height: 1.5;
            background-color: var(--pd-white);
        }

        a {
            text-decoration: none;
            color: inherit;
        }

        ul {
            list-style: none;
        }

        .container {
            max-width: 1200px;
            margin: 0 auto;
            padding: 0 20px;
        }

        /* Top Banner */
        .top-banner {
            background-color: var(--pd-green);
            color: var(--pd-white);
            text-align: center;
            padding: 10px 20px;
            font-size: 14px;
            position: relative;
        }

        .top-banner a {
            color: var(--pd-white);
            text-decoration: underline;
            margin-left: 10px;
            font-weight: 500;
        }

        .banner-close {
            position: absolute;
            right: 20px;
            top: 50%;
            transform: translateY(-50%);
            background: none;
            border: none;
            color: var(--pd-white);
            font-size: 20px;
            cursor: pointer;
        }

        /* Header */
        header {
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 15px 20px;
            border-bottom: 1px solid var(--pd-border);
        }

        .logo {
            font-size: 24px;
            font-weight: 700;
            color: var(--pd-black);
        }

        .main-nav {
            display: flex;
            gap: 25px;
        }

        .main-nav a {
            font-size: 14px;
            font-weight: 500;
            color: var(--pd-black);
        }

        .main-nav a:hover {
            color: var(--pd-green);
        }

        .header-actions {
            display: flex;
            align-items: center;
            gap: 15px;
        }

        .icon-btn {
            background: none;
            border: none;
            font-size: 18px;
            cursor: pointer;
            color: var(--pd-black);
        }

        .btn-primary {
            background-color: var(--pd-green);
            color: var(--pd-white);
            padding: 10px 16px;
            border: none;
            border-radius: 4px;
            font-size: 14px;
            font-weight: 600;
            cursor: pointer;
            transition: background-color 0.2s;
        }

        .btn-primary:hover {
            background-color: var(--pd-green-dark);
        }

        .btn-outline {
            background-color: transparent;
            color: var(--pd-white);
            padding: 10px 16px;
            border: 1px solid var(--pd-white);
            border-radius: 4px;
            font-size: 14px;
            font-weight: 600;
            cursor: pointer;
            transition: background-color 0.2s, color 0.2s;
        }

        .btn-outline:hover {
            background-color: var(--pd-white);
            color: var(--pd-green);
        }

        /* Hero Section */
        .hero {
            display: flex;
            background-color: #dce6dc; /* Light greenish background */
        }

        .hero-left {
            flex: 1;
            background-color: var(--pd-white);
            display: flex;
            align-items: center;
            justify-content: center;
            padding: 40px;
        }

        .servicenow-logo {
            font-size: 40px;
            font-weight: 700;
            color: #83c9a8; /* Green logo color */
            letter-spacing: -1px;
        }

        .hero-right {
            flex: 1;
            background-color: var(--pd-green);
            color: var(--pd-white);
            padding: 60px 40px;
            display: flex;
            flex-direction: column;
            justify-content: center;
        }

        .hero-right h1 {
            font-size: 36px;
            font-weight: 400;
            margin-bottom: 20px;
        }

        .hero-right p {
            font-size: 16px;
            margin-bottom: 30px;
            line-height: 1.6;
        }

        /* Benefits Section */
        .benefits {
            padding: 80px 20px;
        }

        .benefits h2 {
            font-size: 36px;
            font-weight: 400;
            text-align: center;
            margin-bottom: 60px;
        }

        .benefits-grid {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 40px;
        }

        .benefit-item h3 {
            font-size: 24px;
            font-weight: 400;
            margin-bottom: 20px;
        }

        .benefit-item p {
            color: var(--pd-gray-dark);
            font-size: 15px;
        }

        /* About Section */
        .about {
            background-color: var(--pd-black);
            color: var(--pd-white);
            padding: 80px 20px;
        }

        .about h2 {
            font-size: 36px;
            font-weight: 400;
            margin-bottom: 20px;
        }

        .about p {
            font-size: 16px;
            margin-bottom: 30px;
            max-width: 800px;
        }

        /* Resources Section */
        .resources {
            padding: 80px 20px;
        }

        .resources h2 {
            font-size: 36px;
            font-weight: 400;
            margin-bottom: 40px;
        }

        .resources-grid {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 30px;
        }

        .resource-card {
            border-top: 4px solid transparent;
            padding-top: 15px;
        }

        .resource-card.report { border-color: var(--resource-report); }
